import React, { useState, useEffect } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

export default function Productos() {
  const [productos, setProductos] = useState([]);
  const [categorias, setCategorias] = useState([]);
  const [categoriaSeleccionada, setCategoriaSeleccionada] = useState("");
  const [nuevoProducto, setNuevoProducto] = useState({
    ProductoID: "",
    Nombre: "",
    Precio: "",
    Stock: "",
    categoria_id: "",
  });
  const [editando, setEditando] = useState(false);

  const API_PRODUCTOS = "http://localhost:5000/api/productos";
  const API_CATEGORIAS = "http://localhost:5000/api/categorias";

  // Obtener productos
  const obtenerProductos = async () => {
    try {
      const res = await axios.get(API_PRODUCTOS);
      setProductos(res.data);
    } catch (error) {
      console.error("Error al obtener productos:", error);
    }
  };

  // Obtener categorías
  const obtenerCategorias = async () => {
    try {
      const res = await axios.get(API_CATEGORIAS);
      setCategorias(res.data);
    } catch (error) {
      console.error("Error al obtener categorías:", error);
    }
  };

  useEffect(() => {
    obtenerProductos();
    obtenerCategorias();
  }, []);

  // Manejar cambios del formulario
  const handleChange = (e) => {
    const { name, value } = e.target;
    setNuevoProducto((prev) => ({ ...prev, [name]: value }));
  };

  // Agregar o actualizar producto
  const handleSubmit = async (e) => {
    e.preventDefault();

    // preparar payload: asegurar que categoria_id es un número o null
    const payload = {
      ...nuevoProducto,
      // convertir a entero si tiene valor, sino null
      categoria_id:
        nuevoProducto.categoria_id === "" || nuevoProducto.categoria_id === null
          ? null
          : parseInt(nuevoProducto.categoria_id, 10),
      // si Precio/Stock son strings, convertirlos
      Precio: nuevoProducto.Precio === "" ? null : parseFloat(nuevoProducto.Precio),
      Stock: nuevoProducto.Stock === "" ? null : parseInt(nuevoProducto.Stock, 10),
    };

    try {
      console.log("🔁 Enviando payload:", payload);
      if (editando) {
        await axios.put(`${API_PRODUCTOS}/${nuevoProducto.ProductoID}`, payload);
        setEditando(false);
      } else {
        await axios.post(API_PRODUCTOS, payload);
      }

      setNuevoProducto({
        ProductoID: "",
        Nombre: "",
        Precio: "",
        Stock: "",
        categoria_id: "",
      });

      obtenerProductos();
    } catch (error) {
      console.error("Error al guardar producto:", error.response || error);
      // muestra mensaje de error si el backend lo devuelve
      if (error.response && error.response.data) {
        alert("Error del servidor: " + JSON.stringify(error.response.data));
      }
    }
  };

  // Editar producto: aseguramos tipos compatibles con el form
  const editarProducto = (producto) => {
    console.log("✏️ Editando producto:", producto);
    setNuevoProducto({
      ProductoID: producto.ProductoID ?? producto.id ?? "",
      Nombre: producto.Nombre ?? producto.nombre ?? "",
      Precio: producto.Precio ?? producto.precio ?? "",
      Stock: producto.Stock ?? producto.stock ?? "",
      // convertir categoria_id a string para que el select lo seleccione correctamente
      categoria_id:
        producto.categoria_id !== undefined && producto.categoria_id !== null
          ? String(producto.categoria_id)
          : "",
    });
    setEditando(true);
    // opcional: seleccionar filtro para mostrar solo esa categoría en la lista
    if (producto.categoria_id) setCategoriaSeleccionada(String(producto.categoria_id));
  };

  // Eliminar producto
  const eliminarProducto = async (ProductoID) => {
    if (!window.confirm("¿Estás seguro de eliminar este producto?")) return;
    try {
      await axios.delete(`${API_PRODUCTOS}/${ProductoID}`);
      obtenerProductos();
    } catch (error) {
      console.error("Error al eliminar producto:", error);
    }
  };

  // Filtrar productos por categoría seleccionada (si se usa filtro en top)
  const productosFiltrados = categoriaSeleccionada
    ? productos.filter((p) => String(p.categoria_id) === String(categoriaSeleccionada))
    : productos;

  return (
    <div className="container mt-5">
      {/* Filtro por categoría */}
      <div className="mb-4 text-center">
        <label className="form-label fw-bold me-2">Filtrar por categoría:</label>
        <select
          className="form-select d-inline-block w-auto"
          value={categoriaSeleccionada}
          onChange={(e) => setCategoriaSeleccionada(e.target.value)}
        >
          <option value="">Todas</option>
          {categorias.map((c) => (
            <option key={c.id} value={String(c.id)}>
              {c.nombre}
            </option>
          ))}
        </select>
      </div>

      {/* Formulario */}
      <div className="card shadow-lg border-0 rounded-4 mb-5">
        <div className="card-header bg-primary text-white text-center py-3">
          <h2 className="mb-0">{editando ? "Editar Producto" : "Agregar Producto"}</h2>
        </div>

        <div className="card-body">
          <form onSubmit={handleSubmit} className="row g-3">
            <div className="col-md-3">
              <label className="form-label">Nombre</label>
              <input
                type="text"
                name="Nombre"
                value={nuevoProducto.Nombre}
                onChange={handleChange}
                className="form-control"
                required
              />
            </div>

            <div className="col-md-3">
              <label className="form-label">Precio</label>
              <input
                type="number"
                step="0.01"
                name="Precio"
                value={nuevoProducto.Precio}
                onChange={handleChange}
                className="form-control"
                required
              />
            </div>

            <div className="col-md-2">
              <label className="form-label">Stock</label>
              <input
                type="number"
                name="Stock"
                value={nuevoProducto.Stock}
                onChange={handleChange}
                className="form-control"
                required
              />
            </div>

            <div className="col-md-4">
              <label className="form-label">Categoría</label>
              <select
                name="categoria_id"
                value={nuevoProducto.categoria_id}
                onChange={handleChange}
                className="form-select"
                required
              >
                <option value="">Seleccionar</option>
                {categorias.map((c) => (
                  <option key={c.id} value={String(c.id)}>
                    {c.nombre}
                  </option>
                ))}
              </select>
            </div>

            <div className="col-12 text-center mt-3">
              <button
                type="submit"
                className={`btn ${editando ? "btn-warning" : "btn-success"} px-5`}
              >
                {editando ? "Actualizar" : "Agregar"}
              </button>
              {/* botón para cancelar edición */}
              {editando && (
                <button
                  type="button"
                  className="btn btn-secondary ms-3"
                  onClick={() => {
                    setEditando(false);
                    setNuevoProducto({
                      ProductoID: "",
                      Nombre: "",
                      Precio: "",
                      Stock: "",
                      categoria_id: "",
                    });
                  }}
                >
                  Cancelar
                </button>
              )}
            </div>
          </form>
        </div>
      </div>

      {/* Tabla */}
      <div className="card shadow-sm border-0 rounded-4">
        <div className="card-header bg-dark text-white text-center py-3">
          <h3 className="mb-0">Lista de Productos</h3>
        </div>

        <div className="card-body">
          {productosFiltrados.length === 0 ? (
            <p className="text-center text-muted">No hay productos registrados.</p>
          ) : (
            <div className="table-responsive">
              <table className="table table-striped table-hover align-middle text-center">
                <thead className="table-primary">
                  <tr>
                    <th>ID</th>
                    <th>Nombre</th>
                    <th>Precio</th>
                    <th>Stock</th>
                    <th>Categoría</th>
                    <th>Acciones</th>
                  </tr>
                </thead>
                <tbody>
                  {productosFiltrados.map((p) => {
                    const categoria = categorias.find((c) => String(c.id) === String(p.categoria_id));
                    return (
                      <tr key={p.ProductoID}>
                        <td>{p.ProductoID}</td>
                        <td>{p.Nombre}</td>
                        <td>${p.Precio}</td>
                        <td>{p.Stock}</td>
                        <td>{categoria ? categoria.nombre : "Sin categoría"}</td>
                        <td>
                          <button
                            className="btn btn-warning btn-sm me-2"
                            onClick={() => editarProducto(p)}
                            type="button"
                          >
                            Editar
                          </button>
                          <button
                            className="btn btn-danger btn-sm"
                            onClick={() => eliminarProducto(p.ProductoID)}
                            type="button"
                          >
                            Eliminar
                          </button>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
